<div class="page-head"><div><h1>Комментарии</h1><p>Проверка, публикация, отклонение и защита обсуждений от спама.</p></div></div>
<div class="filters"><a class="button <?=$status===''?'primary':''?>" href="<?=e(app_url('/studio/comments'))?>">Все</a><a class="button <?=$status==='pending'?'primary':''?>" href="<?=e(app_url('/studio/comments?status=pending'))?>">Ждут проверки</a><a class="button <?=$status==='approved'?'primary':''?>" href="<?=e(app_url('/studio/comments?status=approved'))?>">Опубликованы</a><a class="button <?=$status==='spam'?'primary':''?>" href="<?=e(app_url('/studio/comments?status=spam'))?>">Спам</a></div>
<?php if($comments):?><div class="comment-list-admin"><?php foreach($comments as $comment):?><article class="comment-row"><div><div class="comment-meta"><b><?=e($comment['author_name'])?></b> · @<?=e($comment['author_username'])?> · <?=e($comment['created_at'])?> · материал «<?=e($comment['entry_title'])?>»</div><p><?=nl2br(e($comment['body']))?></p><span class="status <?=e($comment['status'])?>"><?=e($comment['status'])?></span></div><div class="comment-actions"><?php if($comment['status']!=='approved'):?><form method="post" action="<?=e(app_url('/studio/comments/'.(int)$comment['id'].'/approve'))?>"><?=csrf_field()?><button class="button small primary">Опубликовать</button></form><?php endif;?><?php if($comment['status']!=='pending'):?><form method="post" action="<?=e(app_url('/studio/comments/'.(int)$comment['id'].'/pending'))?>"><?=csrf_field()?><button class="button small">На проверку</button></form><?php endif;?><?php if($comment['status']!=='spam'):?><form method="post" action="<?=e(app_url('/studio/comments/'.(int)$comment['id'].'/spam'))?>"><?=csrf_field()?><button class="button small">Спам</button></form><?php endif;?><form method="post" data-confirm="Удалить комментарий?" action="<?=e(app_url('/studio/comments/'.(int)$comment['id'].'/delete'))?>"><?=csrf_field()?><button class="button small danger">Удалить</button></form></div></article><?php endforeach;?></div><?php else:?><div class="empty-state">В этом разделе комментариев нет.</div><?php endif;?>
